#include <stdio.h>

int vec(int a[2], int b[2]) {
    return a[0] * b[1] - a[1] * b[0];
}

int main() {
    int a_x, a_y, b_x, b_y, c_x, c_y;
    scanf("%d %d", &a_x, &a_y);
    scanf("%d %d", &b_x, &b_y);
    scanf("%d %d", &c_x, &c_y);
    int a[2] = {a_x, a_y};
    int b[2] = {b_x, b_y};
    int c[2] = {c_x, c_y};
    int s[2] = {b[0] - a[0], b[1] - a[1]};
    int d[2] = {c[0] - a[0], c[1] - a[1]};
    int e = vec(s, d);
    if (e < 0) {
        printf("RIGHT\n");
    } else if (e > 0) {
        printf("LEFT\n");
    } else {
        printf("TOWARDS\n");
    }
    return 0;
}
